INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '25e48332-1f4c-4ed8-bee0-1a4c889c0fe5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Routing — Parameters, Grouping, and app.route()$escape$,
  $escape$Hono's router is one of the fastest available, powered by RegExpRouter and TrieRouter under the hood. Define routes directly on the `app` instance using `app.get()`, `app.post()`, etc. Route parameters are captured with `:param` syntax and accessed via `c.req.param('param')`.

For optional segments use `:param?`, for wildcards use `*`. To group related routes, instantiate a new `Hono` app and mount it onto the parent with `app.route('/prefix', subApp)`. This keeps handlers modular without touching the parent router's internals.

Path parameters in the sub-app are relative to its mount point — `/users/:id` on a sub-app mounted at `/api/v1` resolves to `/api/v1/users/:id`. You can also chain methods on the same path using `app.on(['GET', 'POST'], '/path', handler)` or the `.all()` shorthand. For type-safe params, pair routes with Zod validators via `zValidator('param', schema)` from `hono/validator`.$escape$,
  $escape$import { Hono } from 'hono'
import { zValidator } from '@hono/zod-validator'
import { z } from 'zod'

const users = new Hono()

users.get('/', (c) => c.json({ users: [] }))

users.get(
  '/:id',
  zValidator('param', z.object({ id: z.string().uuid() })),
  (c) => {
    const { id } = c.req.valid('param')
    return c.json({ id })
  }
)

users.post('/:id/follow', (c) => {
  const id = c.req.param('id')
  return c.json({ following: id })
})

const app = new Hono()
app.route('/api/v1/users', users)

export default app$escape$,
  $escape$typescript$escape$,
