INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '363f2ea6-237a-4b58-930d-90a01febbff5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Middleware — Pipeline Order, Global vs Route-Scoped$escape$,
  $escape$Hono's middleware runs in the order it's registered, and that order is everything. Global middleware registered via `app.use('*', ...)` runs before every route handler. Route-scoped middleware passed directly into route definitions runs only for that path. The critical detail: middleware registered *after* a route definition won't intercept that route.

Hono uses a `Context` object (`c`) passed through the chain. Each middleware calls `await next()` to hand off to the next handler — skip it and the chain stops. This is how you build abort-early patterns like auth guards.

For route-specific middleware, pass it as an argument before the handler: `app.get('/admin', authMiddleware, handler)`. This keeps concerns local without polluting global scope. You can also scope to a sub-path with `app.use('/api/*', rateLimitMiddleware)` — only routes under `/api/` are affected.

A common gotcha: logging middleware registered after `app.route()` mounts misses those routes entirely. Always register cross-cutting concerns before mounting sub-routers.$escape$,
  $escape$import { Hono } from 'hono'

const app = new Hono()

// Global — runs for every route registered AFTER this line
app.use('*', async (c, next) => {
  console.log(`[${c.req.method}] ${c.req.path}`)
  await next()
})

// Route-scoped auth guard
const authMiddleware = async (c: any, next: any) => {
  const token = c.req.header('Authorization')
  if (!token) return c.json({ error: 'Unauthorized' }, 401)
  await next()
}

app.get('/public', (c) => c.text('No auth needed'))
app.get('/admin', authMiddleware, (c) => c.text('Protected'))

export default app$escape$,
