INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '30f2ad09-7f46-48cc-a176-b4ffb6fc7f5e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Zod Validator — Schema Validation at the Edge$escape$,
  $escape$Hono's `@hono/zod-validator` middleware validates incoming data at the request boundary before your handler ever runs. Attach it per-route using `zValidator('json', schema)` — the first argument targets the target ('json', 'form', 'query', 'param', 'header'). On schema failure, Hono automatically returns a 400 with structured error details; you can override this by passing a custom hook as the third argument to control the error response shape.

Sanitization happens at the Zod layer: use `.trim()`, `.toLowerCase()`, and `.transform()` on fields so handlers receive clean data. Never trust `c.req.valid('json')` without first attaching the validator — it returns the raw body without coercion.

For nested routes or RPC mode, define schemas alongside route definitions so `hc` (the typed client) picks up the contract automatically. This gives you end-to-end type safety from schema definition through to the frontend fetch call, catching mismatches at compile time rather than runtime.$escape$,
  $escape$import { Hono } from 'hono'
import { zValidator } from '@hono/zod-validator'
import { z } from 'zod'

const schema = z.object({
  email: z.string().email().trim().toLowerCase(),
  age: z.coerce.number().int().min(13),
})

const app = new Hono()

app.post(
  '/register',
  zValidator('json', schema, (result, c) => {
    if (!result.success)
      return c.json({ error: 'Invalid input', issues: result.error.flatten() }, 400)
  }),
  (c) => {
    const { email, age } = c.req.valid('json') // fully typed & sanitized
    return c.json({ email, age })
  }
)$escape$,
  $escape$typescript$escape$,
