INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ad0c3dec-7e92-4f3f-9149-5f471b77d9c2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Error Handling — Global Handlers and Consistent Error Responses$escape$,
  $escape$Hono's `app.onError()` hook intercepts any unhandled error thrown inside route handlers or middleware, giving you a single place to shape every error response. Register it once after your routes — Hono calls it with the raw `Error` and the `Context`, so you can inspect `err.constructor` or a custom `statusCode` property before responding.

Pair this with a typed `HTTPException` (re-exported from `hono/http-exception`) so route handlers can throw structured errors without coupling to the response layer. `HTTPException` carries a `status` and optional `res` override, which `onError` can read directly via `err instanceof HTTPException`.

For a consistent envelope, always return `{ success, error: { code, message } }` — never let raw `err.message` leak into production. Use `c.json()` with the appropriate HTTP status so clients get both the status code and a machine-readable payload. Add a `notFound` handler via `app.notFound()` to cover unmatched routes with the same envelope, completing the contract.$escape$,
  $escape$import { Hono } from 'hono'
import { HTTPException } from 'hono/http-exception'

const app = new Hono()

app.get('/secret', (c) => {
  throw new HTTPException(403, { message: 'Forbidden' })
})

app.onError((err, c) => {
  if (err instanceof HTTPException) {
    return c.json({ success: false, error: { code: err.status, message: err.message } }, err.status)
  }
  console.error(err)
  return c.json({ success: false, error: { code: 500, message: 'Internal Server Error' } }, 500)
})

app.notFound((c) => c.json({ success: false, error: { code: 404, message: 'Not Found' } }, 404))

export default app$escape$,
  $escape$typescript$escape$,
