INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8a8de535-e7bd-4b73-8c4a-08e39c772abf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Security Stack — CORS, Rate Limiting, and Hardened Headers in One Pass$escape$,
  $escape$Hono's middleware-first design lets you compose a full security layer before any route handler runs. Use `hono/cors` for CORS with strict origin allowlists — avoid `origin: '*'` in production. Pair it with `hono/secure-headers` which sets `X-Frame-Options`, `X-Content-Type-Options`, `Strict-Transport-Security`, and `Content-Security-Policy` in a single call. For rate limiting, `hono-rate-limiter` integrates natively with Hono's context and supports pluggable stores (memory, Redis via `@hono-rate-limiter/redis`). Against injection, Hono's `c.req.valid()` with Zod schemas is your first line — reject malformed input at the edge before it reaches business logic. Register middleware globally via `app.use('*', ...)` so no route is accidentally unprotected. Order matters: cors → secureHeaders → rateLimiter → your route-specific validators. Run security middleware before any auth middleware to drop bad requests cheaply. Never trust `c.req.header('X-Forwarded-For')` raw for rate-limit keys without validating the proxy chain first.$escape$,
  $escape$import { Hono } from 'hono'
import { cors } from 'hono/cors'
import { secureHeaders } from 'hono/secure-headers'
import { rateLimiter } from 'hono-rate-limiter'

const app = new Hono()

app.use('*', cors({ origin: ['https://app.example.com'], credentials: true }))
app.use('*', secureHeaders())
app.use('*', rateLimiter({ windowMs: 60_000, limit: 100, keyGenerator: (c) => c.req.header('cf-connecting-ip') ?? 'unknown' }))

app.get('/api/data', (c) => c.json({ ok: true }))

export default app$escape$,
  $escape$typescript$escape$,
