INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fc1fba84-ca10-4f7b-a32f-710cff47d1ff',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Performance — Connection Pooling, Async Handlers, and Response Compression$escape$,
  $escape$Hono's edge-native design means performance pitfalls differ from Node.js frameworks. For connection pooling, avoid instantiating DB clients inside handlers — initialize once at the module level and inject via `app.use()` middleware using Hono's `c.set()`/`c.get()` context API. This prevents per-request connection churn, critical on Cloudflare Workers where cold starts are frequent.

Async handlers in Hono are natively awaited — no need for `asyncWrapper` shims. However, avoid `await`-ing inside loops; use `Promise.all()` to parallelize independent DB or API calls within a single handler.

For response compression, Hono's `compress()` middleware (from `hono/compress`) applies gzip/deflate negotiation automatically. On Workers runtime, compression is better delegated to the platform, but on Node.js (`@hono/node-server`) enabling it yields measurable wins for JSON-heavy endpoints. Pair with `c.header('Cache-Control', 'public, max-age=60')` on read-heavy routes to offload repeated computation entirely.$escape$,
  $escape$import { Hono } from 'hono'
import { compress } from 'hono/compress'
import { Pool } from 'pg'

const pool = new Pool({ connectionString: process.env.DATABASE_URL })

const app = new Hono()

app.use('*', async (c, next) => {
  c.set('db', pool)
  await next()
})

app.use('/api/*', compress())

app.get('/api/posts', async (c) => {
  const db = c.get('db')
  const [posts, tags] = await Promise.all([
    db.query('SELECT * FROM posts LIMIT 20'),
    db.query('SELECT * FROM tags')
  ])
  c.header('Cache-Control', 'public, max-age=60')
  return c.json({ posts: posts.rows, tags: tags.rows })
})

export default app$escape$,
