INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af9c9a8c-7e59-4730-bb4e-8e0805cda850',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono API Design — Versioning and OpenAPI Generation Without the Boilerplate$escape$,
  $escape$Hono's `@hono/zod-openapi` package collapses route definition, validation, and spec generation into a single source of truth. Swap `new Hono()` for `new OpenAPIHono()`, then define routes with `createRoute()` — passing Zod schemas for both input and output. The router infers types end-to-end and auto-generates a `/doc` OpenAPI 3.1 spec.

For versioning, use `app.route('/v1', v1Router)` and `app.route('/v2', v2Router)` — each an independent `OpenAPIHono` instance with its own `createRoute` definitions. This keeps v1 contracts frozen while v2 evolves. Mount a `/openapi.json` on each version prefix so consumers can target the exact spec they depend on.

Avoid path-level versioning inside a single router; it muddies the generated spec and couples version lifetimes. Prefer router-per-version — Hono's `route()` composition makes it zero-cost. Use `app.doc('/v2/openapi.json', { openapi: '3.1.0', info: { title: 'ByteAI API v2', version: '2.0.0' } })` to expose the scoped spec.$escape$,
  $escape$import { OpenAPIHono, createRoute, z } from '@hono/zod-openapi'

const v1 = new OpenAPIHono()

const getUser = createRoute({
  method: 'get',
  path: '/users/{id}',
  request: { params: z.object({ id: z.string() }) },
  responses: {
    200: { content: { 'application/json': { schema: z.object({ id: z.string(), name: z.string() }) } }, description: 'User' },
  },
})

v1.openapi(getUser, (c) => {
  const { id } = c.req.valid('param')
  return c.json({ id, name: 'Ada' })
})

v1.doc('/openapi.json', { openapi: '3.1.0', info: { title: 'API v1', version: '1.0.0' } })

const app = new OpenAPIHono()
app.route('/v1', v1)$escape$,
  $escape$typescript$escape$,
