INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a55ff8c2-3e6a-479b-8e4d-3fc1aa048955',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono — Structured Logging with Correlation IDs and Request Middleware$escape$,
  $escape$Hono's `logger()` middleware logs basic request info, but production systems need structured JSON logs with correlation IDs to trace requests across services. Build this by composing a custom middleware before `logger()`. Use `c.set()` to store a generated request ID on the context, then attach it to every log entry downstream. Hono's `Context` object is your single source of truth — pull method, path, status, and duration from it after `await next()`. For correlation IDs from upstream services (e.g. API gateways), read `c.req.header('x-correlation-id')` and fall back to `crypto.randomUUID()`. Pass the ID back in the response via `c.header('x-correlation-id', id)` so clients can reference it. Bind your logger instance to the app via `app.use('*', correlationMiddleware)` before any route handlers — order in Hono is strictly top-down. This pattern works identically across Hono's supported runtimes (Bun, Deno, Cloudflare Workers) since it only uses Web Standard APIs.$escape$,
  $escape$import { Hono } from 'hono'

const app = new Hono()

app.use('*', async (c, next) => {
  const id = c.req.header('x-correlation-id') ?? crypto.randomUUID()
  c.set('requestId', id)
  c.header('x-correlation-id', id)

  const start = Date.now()
  await next()

  console.log(JSON.stringify({
    id,
    method: c.req.method,
    path: c.req.path,
    status: c.res.status,
    duration: Date.now() - start,
  }))
})

app.get('/ping', (c) => c.json({ ok: true }))

export default app$escape$,
