INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1182d1d-e4df-43e4-90a9-101e6ca4fe94',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono Background Jobs — Task Queues and Worker Patterns with Cloudflare Queues$escape$,
  $escape$Hono doesn't ship a built-in job scheduler, but on Cloudflare Workers it integrates cleanly with Cloudflare Queues for durable background processing. You define a queue producer inside any Hono route handler using `c.env.MY_QUEUE.send()`, then handle consumption in the same Worker export via the `queue()` lifecycle hook — completely separate from the HTTP request lifecycle. For scheduled jobs, pair Hono with a `scheduled()` export triggered by a Cron Trigger. The cron handler runs in the same Worker isolate, so it shares bindings (D1, KV, R2) without any extra auth. For Node.js deployments using `@hono/node-server`, there's no native queue primitive — reach for BullMQ backed by Redis instead, and wire the worker process separately from the Hono app entry point. Crucially, never block Hono route handlers with long-running work; offload via `c.executionCtx.waitUntil()` for fire-and-forget tasks that must survive response termination. This keeps p99 latency tight while guaranteeing side-effect completion.$escape$,
  $escape$// worker.ts (Cloudflare Workers)
import { Hono } from 'hono'

const app = new Hono<{ Bindings: { JOB_QUEUE: Queue } }>()

app.post('/enqueue', async (c) => {
  const payload = await c.req.json()
  await c.env.JOB_QUEUE.send(payload)
  return c.json({ queued: true }, 202)
})

export default {
  fetch: app.fetch,
  async queue(batch: MessageBatch<unknown>) {
    for (const msg of batch.messages) {
      await processJob(msg.body)
      msg.ack()
    }
  },
  async scheduled(event: ScheduledEvent, env: Bindings) {
    await runDailyDigest(env)
  },
}$escape$,
