INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd351c839-ca25-42a7-a2d3-950fed50395d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hono — Health Checks, Metrics, and Tracing in Production$escape$,
  $escape$Hono's middleware-first design makes observability clean to implement without heavy dependencies. For health checks, register a `/health` route that probes your DB or upstream dependencies and returns structured JSON — Kubernetes liveness and readiness probes can hit it directly. For metrics, use `hono/timing` to capture per-request durations, then expose a `/metrics` route returning Prometheus-formatted text via a simple counter/histogram store you maintain in a module-level Map. For distributed tracing, Hono integrates with OpenTelemetry via `@opentelemetry/sdk-node` — extract the `traceparent` header in a root middleware using `c.req.header('traceparent')`, create a child span with `tracer.startActiveSpan()`, and propagate context downstream. The `c.set()` / `c.get()` context store is the idiomatic way to thread the active span through handler chains without globals. Combine all three under a dedicated `observability.ts` middleware file and mount it before your route groups so every request is instrumented unconditionally.$escape$,
  $escape$import { Hono } from 'hono'
import { timing } from 'hono/timing'
import { trace, context, propagation } from '@opentelemetry/api'

const app = new Hono()
const tracer = trace.getTracer('hono-app')

app.use('*', timing())

app.use('*', async (c, next) => {
  const ctx = propagation.extract(context.active(), c.req.raw.headers)
  await tracer.startActiveSpan('http.request', {}, ctx, async (span) => {
    span.setAttribute('http.method', c.req.method)
    span.setAttribute('http.route', c.req.path)
    c.set('span', span)
    await next()
    span.setAttribute('http.status_code', c.res.status)
    span.end()
  })
})

app.get('/health', (c) => c.json({ status: 'ok', db: 'reachable', ts: Date.now() }))

export default app$escape$,
